import React from 'react';
import { useWishlist } from '../context/WishlistContext';

export default function ProductCounter({ product }) {
  const { wishlistItems, addToWishlist, updateQuantity } = useWishlist();

  const identifier = product.cartId || product.id;
  const cartItem = wishlistItems.find(item => (item.cartId || item.id) === identifier);
  const quantity = cartItem ? cartItem.quantity : 0;

  const handleAdd = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (quantity === 0) {
      addToWishlist(product);
    } else {
      updateQuantity(identifier, quantity + 1);
    }
  };

  const handleRemove = (e) => {
    e.preventDefault();
    e.stopPropagation();
    updateQuantity(identifier, quantity - 1);
  };

  if (quantity === 0) {
    return (
      <button 
        onClick={handleAdd} 
        style={{
          width: '36px', height: '36px', borderRadius: '50%', backgroundColor: 'var(--primary)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '20px', transition: 'all 0.2s', border: 'none', cursor: 'pointer'
        }}
      >
        +
      </button>
    );
  }

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', backgroundColor: 'var(--surface-container-high)', padding: '4px', borderRadius: '24px' }} onClick={e => e.stopPropagation()}>
      <button 
        onClick={handleRemove}
        style={{ width: '28px', height: '28px', borderRadius: '50%', backgroundColor: 'var(--surface-container-lowest)', color: 'var(--on-surface)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '18px', border: '1px solid var(--outline-variant)', cursor: 'pointer' }}
      >
        -
      </button>
      <span className="font-label-md" style={{ width: '20px', textAlign: 'center' }}>{quantity}</span>
      <button 
        onClick={handleAdd}
        style={{ width: '28px', height: '28px', borderRadius: '50%', backgroundColor: 'var(--primary)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '18px', border: 'none', cursor: 'pointer' }}
      >
        +
      </button>
    </div>
  );
}
